import sys


def main():
    a, b, f, k = map(int, input().split())
    if f > a:
        print(-1)
        return

    if a - f < b:
        print(-1)
        return

    ans = 0
    cnt = 0
    while cnt < k:
        if f <= a - b:
            ans += 1
        elif a - b < f <= a:
            ans += 2
        else:
            ans += 1
        cnt += 1

    print(ans)


if __name__ == '__main__':
    main()
